export type MotionType =
	| typeof Api.MOTION_TYPE_DYNAMIC
	| typeof Api.MOTION_TYPE_STATIC
	| typeof Api.MOTION_TYPE_KINEMATIC;

/**
 * What an animation clip does once it reaches its end:
 * - `loop` — restart from the beginning, indefinitely.
 * - `once` — play through once, then clear the clip (base returns to locomotion, layers stop).
 * - `hold` — play through once, then freeze on the final frame until explicitly stopped.
 */
export type AnimationPlaybackMode = "loop" | "once" | "hold";

export type TraitId = string;
export type TraitTargetId = string | number;

export type TraitDefinition = {
	id: string;
	schema?: Schema;
	meta?: TraitMeta;
};

