// Inline GLB component descriptor. `id` keys the shared `geometryById` map; `colors`
// optionally overrides per-material palette colors ("01".."05"). Client-only.
export type GlbMeshSpec = {
	id: CharacterComponentId;
	colors?: CharacterAvatarComponentColors;
};

